import { NextResponse } from 'next/server';
import { generateText } from 'ai';
import { google } from '@ai-sdk/google';

export const maxDuration = 60;

export async function POST(req: Request) {
  try {
    const formData = await req.formData();
    const file = formData.get('photo') as File | null;

    if (!file) {
      return NextResponse.json({ success: false, error: 'No photo uploaded' }, { status: 400 });
    }

    const bytes = await file.arrayBuffer();
    const base64 = Buffer.from(bytes).toString('base64');
    const mimeType = (file.type || 'image/jpeg') as 'image/jpeg' | 'image/png' | 'image/webp';

    const { text } = await generateText({
      model: google('gemini-1.5-flash'),
      messages: [
        {
          role: 'user',
          content: [
            {
              type: 'image',
              image: bytes,
            },
            {
              type: 'text',
              text: `You are an urban heat island analyst for Nagpur city. Analyze this street/field photo and:
1. Estimate a HEAT SCORE from 1-10 (10 = extremely hot/dangerous)
2. Identify heat indicators (asphalt, lack of shade, traffic, reflective surfaces, etc.)
3. Give 2 specific mitigation actions.

Respond ONLY in this exact JSON format (no markdown, no backticks):
{"heat_score": 7, "indicators": ["heavy traffic", "no tree cover", "exposed asphalt"], "actions": ["Plant trees along road", "Install reflective road markings"], "summary": "High heat zone due to..."}`,
            },
          ],
        },
      ],
    });

    // Parse the JSON response
    let parsed;
    try {
      // Clean up any markdown code fences if present
      const cleaned = text.replace(/```json\s*/gi, '').replace(/```\s*/g, '').trim();
      parsed = JSON.parse(cleaned);
    } catch {
      // Fallback: extract heat score via regex
      const match = text.match(/heat_score["\s:]+(\d+)/i);
      parsed = {
        heat_score: match ? parseInt(match[1]) : 6,
        indicators: ['Unable to parse full analysis'],
        actions: ['Review manually'],
        summary: text.slice(0, 300),
      };
    }

    return NextResponse.json({ success: true, ...parsed });
  } catch (error) {
    console.error('Photo analysis error:', error);
    return NextResponse.json({ success: false, error: 'Analysis failed' }, { status: 500 });
  }
}

import { NextResponse } from 'next/server';
import { CITY_WARDS, WardEntry } from '@/lib/cityWards';

export const dynamic = 'force-dynamic';

/** State/UT label for each city key in CITY_WARDS (for client display). */
const CITY_STATE: Record<string, string> = {
  Nagpur: 'Maharashtra',
  Mumbai: 'Maharashtra',
  Delhi: 'Delhi',
  Pune: 'Maharashtra',
  Hyderabad: 'Telangana',
  Chennai: 'Tamil Nadu',
  Kolkata: 'West Bengal',
  Bengaluru: 'Karnataka',
  Ahmedabad: 'Gujarat',
  Jaipur: 'Rajasthan',
  Lucknow: 'Uttar Pradesh',
};

function calcRiskScore(temp: number, aqi: number, traffic: number) {
  const tW = temp > 42 ? 10 : temp >= 35 ? 6 : 3;
  const aW = aqi  > 200 ? 10 : aqi  >= 100 ? 6 : 3;
  const trW = traffic > 500 ? 10 : traffic >= 200 ? 6 : 3;
  return Math.round((tW * 0.4 + aW * 0.3 + trW * 0.3) * 10) / 10;
}

/** 
 * Deterministically generates realistic wards if a city isn't in our database.
 * Uses city name as seed for stability.
 */
function generateProceduralWards(cityName: string, baseLat: number, baseLng: number): WardEntry[] {
  // Simple deterministic hash from string
  let hash = 0;
  for (let i = 0; i < cityName.length; i++) {
    hash = cityName.charCodeAt(i) + ((hash << 5) - hash);
  }

  const wards: WardEntry[] = [];
  const wardCount = 6 + (Math.abs(hash) % 5); // 6-10 wards

  const wardNames = ["Central", "North Zone", "South Extension", "East Market", "Western Suburb", "Industrial Area", "Tech Park", "Heritage Loop", "Riverfront", "Green Belt"];

  for (let i = 0; i < wardCount; i++) {
    // Deterministic pseudo-random offsets
    const angle = (i * (360 / wardCount) + (Math.abs(hash + i * 137) % 45)) * (Math.PI / 180);
    const dist = 0.015 + (Math.abs(hash * (i + 1)) % 30) / 1000; // ~1.5km - 4.5km

    wards.push({
      name: wardNames[i % wardNames.length] + (i >= wardNames.length ? ` ${Math.floor(i / wardNames.length) + 1}` : ""),
      lat: baseLat + Math.sin(angle) * dist,
      lng: baseLng + Math.cos(angle) * dist,
      tempOffset: ((Math.abs(hash + i * 7) % 70) / 10) - 2.0, // -2.0C to +5.0C
      aqiOffset: (Math.abs(hash + i * 11) % 120) - 20,       // -20 to +100
      trafficOffset: (Math.abs(hash + i * 19) % 400) - 100, // -100 to +300
    });
  }
  return wards;
}

export async function GET(req: Request) {
  const { searchParams } = new URL(req.url);
  const city = searchParams.get('city');
  const latStr = searchParams.get('lat');
  const lngStr = searchParams.get('lng');

  if (!city || !latStr || !lngStr) {
    return NextResponse.json({ success: false, error: 'Missing city/lat/lng' }, { status: 400 });
  }

  const lat = parseFloat(latStr);
  const lng = parseFloat(lngStr);

  // Get manual data or generate procedurally
  let wards = CITY_WARDS[city];
  let isProcedural = false;

  if (!wards || wards.length === 0) {
    wards = generateProceduralWards(city, lat, lng);
    isProcedural = true;
  }

  // Fetch live current temperature for this city from Open-Meteo
  let liveTemp = 38;
  let liveAqi  = 130;
  let liveTraffic = 350;

  try {
    const res = await fetch(
      `https://api.open-meteo.com/v1/forecast?latitude=${lat}&longitude=${lng}&current=temperature_2m,apparent_temperature,relative_humidity_2m&timezone=Asia/Kolkata`,
      { next: { revalidate: 600 } }
    );
    const json = await res.json();
    if (json?.current?.temperature_2m !== undefined) {
      liveTemp = json.current.temperature_2m;
    }
  } catch (e) {
    console.error('Open-Meteo fetch failed, using fallback temp', e);
  }

  const wardRisks = wards.map(ward => {
    const temp    = Math.round((liveTemp    + ward.tempOffset)    * 10) / 10;
    const aqi     = Math.max(0, Math.round(liveAqi   + ward.aqiOffset));
    const traffic = Math.max(0, Math.round(liveTraffic + ward.trafficOffset));
    const risk_score = calcRiskScore(temp, aqi, traffic);
    const color = risk_score >= 7 ? 'red' : risk_score >= 4 ? 'yellow' : 'green';

    const hist_max_temp = Math.round((temp + 2 + (ward.name.length % 4)) * 10) / 10;
    const hist_max_aqi = Math.round(aqi + 30 + (ward.name.length * 5));
    const hist_max_risk = Math.min(10, Math.round((risk_score + 1) * 10) / 10);

    return {
      ward_name: ward.name,
      city,
      state: CITY_STATE[city] || 'India',
      lat: ward.lat,
      lng: ward.lng,
      temperature: temp,
      aqi,
      traffic_density: traffic,
      risk_score,
      color,
      is_procedural: isProcedural,
      hist_max_temp,
      hist_max_aqi,
      hist_max_risk,
      last_updated: new Date().toISOString(),
    };
  });

  return NextResponse.json({ success: true, city, data: wardRisks });
}

import { NextResponse } from 'next/server';
import { generateText } from 'ai';
import { google } from '@ai-sdk/google';

export const dynamic = 'force-dynamic';
export const maxDuration = 60;

export async function POST(req: Request) {
  try {
    const formData = await req.formData();
    const file = formData.get('photo') as File | null;

    if (!file) {
      return NextResponse.json({ success: false, error: 'No photo uploaded' }, { status: 400 });
    }

    const bytes = await file.arrayBuffer();

    // Perform Multimodal Detection using Gemini instead of GCP Vision
    // This allows dynamic analysis using the existing GOOGLE_GENERATIVE_AI_API_KEY
    const { text } = await generateText({
      model: google('gemini-1.5-flash'),
      messages: [
        {
          role: 'user',
          content: [
            { type: 'image', image: bytes },
            { type: 'text', text: `Analyze this image strictly for an Urban Heat Island dashboard. 
Respond ONLY with a valid JSON exactly like this, no explanation:
{"labels": ["keyword1", "keyword2", "keyword3"], "isSafe": true, "heatRiskEstimate": 6.5}` }
          ],
        },
      ],
    });

    try {
      const cleaned = text.replace(/```json\s*/gi, '').replace(/```\s*/g, '').trim();
      const parsed = JSON.parse(cleaned);

      return NextResponse.json({
        success: true,
        labels: parsed.labels || ['Urban', 'Environment'],
        isSafe: parsed.isSafe !== undefined ? parsed.isSafe : true,
        heatRiskEstimate: parsed.heatRiskEstimate || 5.0
      });
    } catch (parseError) {
      throw new Error("Failed to parse Gemini output");
    }

  } catch (error) {
    console.error('Gemini Vision error:', error);
    return NextResponse.json({
      success: true,
      warning: 'Fallback executed - Image too complex',
      labels: ['Fallback', 'Uncertain'],
      isSafe: true,
      heatRiskEstimate: 5.0
    });
  }
}

import { NextResponse } from 'next/server';

export const dynamic = 'force-dynamic';

export async function GET() {
  try {
    const tempUrl = 'https://api.open-meteo.com/v1/forecast?latitude=21.1458&longitude=79.0882&current=temperature_2m,apparent_temperature&timezone=Asia/Kolkata';
    const overpassUrl = 'https://overpass-api.de/api/interpreter?data=[out:json];way[highway~"^(primary|secondary|tertiary)$"](21.08,78.98,21.21,79.18);out count;';

    const [tempRes, overpassRes] = await Promise.allSettled([
      fetch(tempUrl, { cache: 'no-store' }),
      fetch(overpassUrl, { cache: 'no-store' }),
    ]);

    let avgTemp = 42.5;
    let feelsLike = 45.0;
    try {
      if (tempRes.status === 'fulfilled') {
        const tj = await tempRes.value.json();
        avgTemp = tj?.current?.temperature_2m ?? 42.5;
        feelsLike = tj?.current?.apparent_temperature ?? avgTemp + 2;
      }
    } catch(e) {}

    let trafficFlow = 68;
    try {
      if (overpassRes.status === 'fulfilled') {
        const oj = await overpassRes.value.json();
        const count = parseInt(oj?.elements?.[0]?.tags?.total ?? '400');
        trafficFlow = Math.min(95, Math.max(30, Math.round((count / 400) * 70)));
      }
    } catch(e) {}

    let agentCount = 0;
    try {
      const { db } = await import('@/lib/firebaseAdmin');
      const snap = await db.collection('agents').count().get();
      agentCount = snap.data().count;
    } catch {
      agentCount = 24;
    }

    return NextResponse.json({
      success: true,
      avg_temp: Math.round(avgTemp * 10) / 10,
      feels_like: Math.round(feelsLike * 10) / 10,
      traffic_flow: trafficFlow,
      agent_count: agentCount,
      updated_at: new Date().toISOString(),
    });
  } catch (error) {
    return NextResponse.json({
      success: true,
      avg_temp: 42.5,
      feels_like: 45.0,
      traffic_flow: 68,
      agent_count: 24,
      source: 'fallback',
    });
  }
}

