interface MapProps {
  onZoneClick: (zone: ZoneData) => void;
  selectedZone?: ZoneData | null;
}

function MapController({ selectedCity, selectedZone }: { selectedCity: string | null; selectedZone?: ZoneData | null }) {
  const map = useMap();
  useEffect(() => {
    if (selectedZone) {
      map.flyTo([selectedZone.lat, selectedZone.lng], 14, { duration: 1.5 });
    } else if (selectedCity) {
      const city = INDIA_CITIES.find(c => c.ward_name === selectedCity);
      if (city) map.flyTo([city.lat, city.lng], 12, { duration: 1.5 });
    } else {
      map.flyTo(INDIA_CENTER, 5, { duration: 1.5 });
    }
  }, [selectedCity, selectedZone, map]);
  return null;
}

export default function Map({ onZoneClick, selectedZone }: MapProps) {
  const [selectedCity, setSelectedCity] = useState<string | null>(null);
  const [liveWards, setLiveWards] = useState<ZoneData[] | null>(null);
  const [wardsLoading, setWardsLoading] = useState(false);
  const [wardsFetchError, setWardsFetchError] = useState(false);

  // If a city is selected, we show wards. Otherwise we show major India cities.
  const displayZones = selectedCity && liveWards ? liveWards : INDIA_CITIES;

  useEffect(() => {
    if (!selectedCity) {
      setLiveWards(null);
      setWardsFetchError(false);
      return;
    }

    const apiCity = CITY_API_KEY[selectedCity] ?? selectedCity;
    const center = INDIA_CITIES.find(c => c.ward_name === selectedCity);
    if (!center) return;

    const ac = new AbortController();
    setWardsLoading(true);
    setWardsFetchError(false);

    const url = `/api/city-wards?city=${encodeURIComponent(apiCity)}&lat=${center.lat}&lng=${center.lng}`;

    fetch(url, { signal: ac.signal })
      .then(res => res.json())
      .then(json => {
        if (!json.success || !Array.isArray(json.data)) {
          setWardsFetchError(true);
          setLiveWards(null);
          return;
        }
        setLiveWards(json.data);
      })
      .catch(() => {
        if (!ac.signal.aborted) {
          setWardsFetchError(true);
          setLiveWards(null);
        }
      })
      .finally(() => {
        if (!ac.signal.aborted) setWardsLoading(false);
      });

    return () => ac.abort();
  }, [selectedCity]);

  const handleMarkerClick = (zone: ZoneData) => {
    // If clicking a city that has ward-level data, drill in and show wards
    if (!selectedCity) {
      setSelectedCity(zone.ward_name);
      onZoneClick(zone); // report city-level click to parent
    } else {
      onZoneClick(zone); // ward-level click
    }
  };

  return (
    <div className="w-full h-full z-0 relative">
      {/* Back button when drilled into a city */}
      {selectedCity && (
        <div className="absolute top-24 left-4 z-[1000] flex flex-col gap-2">
          <button
            onClick={() => {
              setSelectedCity(null);
              setLiveWards(null);
              setWardsFetchError(false);
            }}
            className="bg-black/80 backdrop-blur-md text-emerald-400 text-xs font-bold px-4 py-2 rounded-full border border-emerald-500/30 hover:bg-black transition-all flex items-center gap-2"
          >
            ??? Back to India
          </button>

          <div className="bg-black/80 backdrop-blur-md text-white/90 text-[10px] font-bold px-4 py-2 rounded-full border border-white/10">
            ???? <span className="text-emerald-400 uppercase tracking-widest">{selectedCity}</span>
            {wardsLoading ? " ?? loading live zones..." : liveWards ? ` ?? ${liveWards.length} zones active` : ""}
            {wardsFetchError && " ?? API Offline"}
          </div>
        </div>
      )}

      {selectedCity && liveWards && (
        <div className="absolute bottom-4 right-4 left-4 md:left-auto z-[1000] w-full md:w-[22rem] max-h-[min(40vh,320px)] flex flex-col rounded-xl border border-white/10 bg-black/85 backdrop-blur-md shadow-xl overflow-hidden">
          <div className="px-3 py-2 border-b border-white/10 shrink-0">
            <div className="text-[11px] font-bold text-emerald-400 uppercase tracking-wide">Areas & current zones</div>
            <div className="text-[10px] text-white/50 mt-0.5">
              {liveWards[0]?.last_updated ? `As of ${new Date(liveWards[0].last_updated).toLocaleString()}` : "Real-time Feed"}
            </div>
          </div>
          <div className="overflow-y-auto flex-1 min-h-0">
            {liveWards.map((z) => {
              const hex = z.color === 'red' ? '#ef4444' : z.color === 'yellow' ? '#eab308' : '#10b981';
              return (
                <div
                  key={z.ward_name}
                  className="px-3 py-2 border-b border-white/5 flex items-start justify-between gap-2 hover:bg-white/5 transition-colors cursor-pointer"
                  onClick={() => onZoneClick(z)}
                >
                  <div className="min-w-0">
                    <div className="text-xs font-semibold text-white truncate">{z.ward_name}</div>
                    <div className="text-[10px] text-white/45">Risk {z.risk_score}/10</div>
                  </div>
                  <div className="text-[10px] font-bold shrink-0 text-right" style={{ color: hex }}>
                    {z.temperature}??C | AQI {z.aqi}
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      )}

      <MapContainer
        center={INDIA_CENTER}
        zoom={5}
        scrollWheelZoom={true}
        style={{ height: '100%', width: '100%', background: '#0d1218' }}
        zoomControl={false}
        minZoom={4}
        maxZoom={18}
      >
        <TileLayer
          attribution="&copy; ESRI World Imagery"
          url="https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}"
        />

        <MapController selectedCity={selectedCity} selectedZone={selectedZone} />

        {displayZones.map((zone) => {
          const colorHex = zone.color === 'red' ? '#ef4444' : zone.color === 'yellow' ? '#eab308' : '#10b981';
          const isSelected = selectedZone?.ward_name === zone.ward_name;

          return (
            <CircleMarker
              key={zone.ward_name + (selectedCity || "India")}
              center={[zone.lat, zone.lng]}
              radius={isSelected ? 18 : selectedCity ? 12 : 9}
              pathOptions={{
                color: colorHex,
                fillColor: colorHex,
                fillOpacity: isSelected ? 0.95 : 0.65,
                weight: isSelected ? 3 : 1.5,
              }}
              eventHandlers={{ click: () => handleMarkerClick(zone) }}
            >
              <Tooltip direction="top" offset={[0, -10]} opacity={0.97}>
                <div style={{ fontFamily: 'monospace', padding: '2px 0', minWidth: 160 }}>
                  <div style={{ fontWeight: 'bold', color: colorHex, fontSize: 13 }}>
                    {zone.ward_name} {!selectedCity ? "????" : ""}
                  </div>
                  <div style={{ color: '#aaa', fontSize: 10 }}>{zone.state}</div>
                  <div style={{ color: '#ccc', fontSize: 11, marginTop: 4 }}>
                    Risk: <b style={{ color: colorHex }}>{zone.risk_score}/10</b>
                    &nbsp;???&nbsp;{zone.temperature}??C
                  </div>
                  <div style={{ color: '#888', fontSize: 10 }}>
                    AQI {zone.aqi} &nbsp;???&nbsp; Traffic {zone.traffic_density} v/h
                  </div>
                  {!selectedCity && (
                    <div style={{ color: '#666', fontSize: 9, marginTop: 4, fontStyle: 'italic' }}>
                      Click to drill into city areas
                    </div>
                  )}
                </div>
              </Tooltip>
            </CircleMarker>
          );
        })}
      </MapContainer>
    </div>
  );
}

'use client';

import React, { useState, useEffect } from 'react';
import { supabase } from '@/lib/supabaseClient';

interface OfficerAccessProps {
  onAuthorize: () => void;
}

export default function OfficerAccess({ onAuthorize }: OfficerAccessProps) {
  const [activeTab, setActiveTab] = useState<'login' | 'register'>('login');

  // Form States
  const [email, setEmail] = useState('');
  const [mobile, setMobile] = useState('');
  const [badgeId, setBadgeId] = useState('');

  // UI States
  const [isLoading, setIsLoading] = useState(false);
  const [message, setMessage] = useState<{ text: string, type: 'error' | 'success' | 'info' } | null>(null);

  // Hardcoded required password/badge
  const REQUIRED_BADGE = 'IND-NEXUS-001';

  const handleRegister = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!email || !mobile) {
      setMessage({ text: 'Email and Mobile Number are required.', type: 'error' });
      return;
    }

    setIsLoading(true);
    setMessage({ text: 'INITIATING SECURE REGISTRATION...', type: 'info' });

    try {
      // Register with Supabase using email and the badge ID as the password
      const { data, error } = await supabase.auth.signUp({
        email,
        password: REQUIRED_BADGE, // Using badge ID as password behind the scenes
        options: {
          data: {
            mobile_number: mobile,
          }
        }
      });

      if (error) {
        setMessage({ text: `DENIED: ${error.message}`, type: 'error' });
      } else {
        setMessage({ text: 'REGISTRATION LOGGED. Check your email to confirm clearance before logging in.', type: 'success' });
        // Clear fields
        setEmail('');
        setMobile('');
        setTimeout(() => setActiveTab('login'), 3000);
      }
    } catch (err: any) {
      setMessage({ text: 'NETWORK FAILURE.', type: 'error' });
    }
    setIsLoading(false);
  };

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!email || !badgeId) {
      setMessage({ text: 'CREDENTIALS REQUIRED.', type: 'error' });
      return;
    }

    setIsLoading(true);
    setMessage({ text: 'AUTHENTICATING CLEARANCE...', type: 'info' });

    try {
      // Login with Supabase
      const { data, error } = await supabase.auth.signInWithPassword({
        email,
        password: badgeId // User inputs IND-NEXUS-001 as their Badge ID/Password
      });

      if (error) {
        setMessage({ text: `ACCESS DENIED: ${error.message}`, type: 'error' });
      } else {
        setMessage({ text: 'CLEARANCE GRANTED. WELCOME OFFICER.', type: 'success' });
        setTimeout(() => {
          onAuthorize();
        }, 1500);
      }
    } catch (err: any) {
      setMessage({ text: 'NETWORK FAILURE.', type: 'error' });
    }
    setIsLoading(false);
  };

  return (
    <div className="fixed inset-0 z-[100] bg-black flex flex-col items-center justify-center font-mono overflow-hidden">
      <div className="absolute inset-0 opacity-20 pointer-events-none" 
           style={{ backgroundImage: 'radial-gradient(circle at center, #10b981 0%, transparent 100%)', backgroundSize: '150% 150%', backgroundPosition: 'center' }} />

      <div className="w-[450px] max-w-[90%] p-8 border border-emerald-900/50 rounded-xl relative z-10 bg-black/80 shadow-[0_0_50px_rgba(16,185,129,0.08)] backdrop-blur-md">

        <div className="text-center mb-8">
          <div className="inline-flex items-center justify-center w-12 h-12 rounded-full bg-emerald-500/10 border border-emerald-500/30 mb-4">
             <span className="text-emerald-500 text-xl font-black">N</span>
          </div>
          <h2 className="text-emerald-500 font-bold tracking-widest text-lg">NEXUS COMMAND API</h2>
          <p className="text-emerald-900 text-xs tracking-widest mt-1">SECURE CLEARANCE REQUIRED</p>
        </div>

        {/* Custom Tabs */}
        <div className="flex border-b border-emerald-900/50 mb-6">
          <button 
            onClick={() => { setActiveTab('login'); setMessage(null); }}
            className={`flex-1 py-2 text-xs font-bold tracking-widest transition-colors ${activeTab === 'login' ? 'text-emerald-400 border-b-2 border-emerald-400' : 'text-emerald-900 hover:text-emerald-700'}`}
          >
            AUTHORIZE (LOGIN)
          </button>
          <button 
            onClick={() => { setActiveTab('register'); setMessage(null); }}
            className={`flex-1 py-2 text-xs font-bold tracking-widest transition-colors ${activeTab === 'register' ? 'text-emerald-400 border-b-2 border-emerald-400' : 'text-emerald-900 hover:text-emerald-700'}`}
          >
            REGISTER BADGE
          </button>
        </div>

        {message && (
          <div className={`p-3 mb-6 border rounded text-xs tracking-widest text-center animate-pulse ${
            message.type === 'error' ? 'bg-red-500/10 border-red-500/50 text-red-500' : 
            message.type === 'success' ? 'bg-emerald-500/10 border-emerald-500/50 text-emerald-400' : 
            'bg-amber-500/10 border-amber-500/50 text-amber-500'
          }`}>
            {message.text}
          </div>
        )}

        {activeTab === 'register' ? (
          <form onSubmit={handleRegister} className="space-y-5">
            <div>
              <label className="block text-[10px] text-emerald-600 font-bold tracking-widest mb-1">OFFICER EMAIL</label>
              <input 
                type="email" 
                required
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                className="w-full bg-black/50 border border-emerald-900/50 text-emerald-400 text-sm tracking-wider px-4 py-2 focus:outline-none focus:border-emerald-500 transition-colors"
                placeholder="officer@nexus.gov.in"
              />
            </div>
            <div>
              <label className="block text-[10px] text-emerald-600 font-bold tracking-widest mb-1">SECURE COMMS (MOBILE)</label>
              <input 
                type="tel" 
                required
                value={mobile}
                onChange={(e) => setMobile(e.target.value)}
                className="w-full bg-black/50 border border-emerald-900/50 text-emerald-400 text-sm tracking-wider px-4 py-2 focus:outline-none focus:border-emerald-500 transition-colors"
                placeholder="+91 XXXXX XXXXX"
              />
            </div>
            <button 
              type="submit" 
              disabled={isLoading}
              className="w-full bg-emerald-950 hover:bg-emerald-900 text-emerald-400 font-bold tracking-widest text-sm py-3 border border-emerald-800 disabled:opacity-50 transition-colors mt-2"
            >
              {isLoading ? 'PROCESSING...' : 'REQUEST CLEARANCE'}
            </button>
          </form>
        ) : (
          <form onSubmit={handleLogin} className="space-y-5">
            <div>
              <label className="block text-[10px] text-emerald-600 font-bold tracking-widest mb-1">OFFICER EMAIL</label>
              <input 
                type="email" 
                required
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                className="w-full bg-black/50 border border-emerald-900/50 text-emerald-400 text-sm tracking-wider px-4 py-2 focus:outline-none focus:border-emerald-500 transition-colors"
                placeholder="officer@nexus.gov.in"
              />
            </div>
            <div>
              <label className="block text-[10px] text-emerald-600 font-bold tracking-widest mb-1">SECURITY BADGE ID</label>
              <input 
                type="text" 
                required
                value={badgeId}
                onChange={(e) => setBadgeId(e.target.value.toUpperCase())}
                className="w-full bg-black/50 border border-emerald-900/50 text-emerald-400 text-sm tracking-wider px-4 py-2 focus:outline-none focus:border-emerald-500 transition-colors placeholder:text-emerald-900/30"
                placeholder="IND-NEXUS-XXX"
              />
            </div>
            <button 
              type="submit" 
              disabled={isLoading}
              className="w-full bg-emerald-950 hover:bg-emerald-900 text-emerald-400 font-bold tracking-widest text-sm py-3 border border-emerald-800 disabled:opacity-50 transition-colors mt-2"
            >
              {isLoading ? 'AUTHENTICATING...' : 'ENTER DASHBOARD'}
            </button>
          </form>
        )}
      </div>

      {/* Scanline effect overlay */}
      <div className="absolute inset-0 pointer-events-none bg-[url('data:image/svg+xml;base64,PHN2ZyB4bWxucz0iaHR0cDovL3d3dy53My5vcmcvMjAwMC9zdmciIHdpZHRoPSI0IiBoZWlnaHQ9IjQiPjxyZWN0IHdpZHRoPSI0IiBoZWlnaHQ9IjIiIGZpbGw9InJnYmEoMCwwLDAsMC4xKSIvPjwvc3ZnPg==')] opacity-50 z-50"></div>
    </div>
  );
}
